import React from 'react';
import { Link } from 'react-router-dom';

const Footer = () => {
    const currentYear = new Date().getFullYear();

    return (
        <footer style={styles.footerContainer}>
            <div style={styles.contentWrapper}>
                {/* Copyright y Nombre del Equipo */}
                <p style={styles.copyrightText}>
                    © {currentYear} Repositorio Bicentenario de Bolivia. Todos los derechos reservados.
                    <span style={styles.teamName}> Trinity Team</span>.
                </p>

                <div style={styles.mainContent}>
                    {/* Sección de Navegación */}
                    <div style={styles.section}>
                        <h3 style={styles.sectionTitle}>Navegación</h3>
                        <ul style={styles.linkList}>
                            <li><Link to="/" style={styles.link}>Inicio</Link></li>
                            <li><Link to="/login" style={styles.link}>Login</Link></li>
                            <li><Link to="/register" style={styles.link}>Registro</Link></li>
                        </ul>
                    </div>

                    {/* Sección de Redes Sociales */}
                    <div style={styles.section}>
                        <h3 style={styles.sectionTitle}>Redes Sociales</h3>
                        <div style={styles.socialIcons}>
                            {/* ASEGÚRATE de que estos archivos PNG existan en public/media/icons/ */}
                            <a href="https://www.facebook.com/TuPaginaDeFacebook" target="_blank" rel="noopener noreferrer" style={styles.socialIconLink}>
                                <img src="/media/icons/facebook_icon.png" alt="Facebook" style={styles.socialIconImage} />
                            </a>
                            <a href="https://www.instagram.com/TuCuentaDeInstagram" target="_blank" rel="noopener noreferrer" style={styles.socialIconLink}>
                                <img src="/media/icons/instagram_icon.png" alt="Instagram" style={styles.socialIconImage} />
                            </a>
                            <a href="https://www.tiktok.com/@TuCuentaDeTikTok" target="_blank" rel="noopener noreferrer" style={styles.socialIconLink}>
                                <img src="/media/icons/tiktok_icon.png" alt="TikTok" style={styles.socialIconImage} />
                            </a>
                        </div>
                    </div>

                    {/* Sección Sobre el Repositorio */}
                    <div style={styles.section}>
                        <h3 style={styles.sectionTitle}>Sobre el Repositorio</h3>
                        <p style={styles.aboutText}>
                            Plataforma digital para consulta, preservación y análisis de documentos históricos bolivianos. Proyecto del Bicentenario 2025.
                        </p>
                    </div>
                </div>

                {/* Cita final */}
                <p style={styles.quoteText}>
                    “Conocer nuestra historia es entender nuestro presente.”
                </p>

                {/* Crédito de Alberto Navarro, discreto y bonito */}
                <p style={styles.navarroCredit}>Desarrollado por Alberto Navarro</p>

            </div>
        </footer>
    );
};

const styles = {
    footerContainer: {
        // IMAGEN DE FONDO: Asegúrate de que footer2.png está en public/media/
        backgroundImage: "url('/media/footer2.png')", //
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        backgroundRepeat: 'no-repeat',
        backgroundColor: '#F8F6F1', // Un beige suave de respaldo
        color: '#4a4a4a', // Color de texto principal
        fontFamily: "'Inter', 'ui-sans-serif', 'system-ui', sans-serif",
        padding: '15px 0', // Padding vertical MUCHO MENOR para reducir la altura
        marginTop: 'auto', // Para que se pegue al final de la página
        boxShadow: '0 -2px 8px rgba(0,0,0,0.02)', // Sombra muy sutil
        transition: 'background-color 0.3s ease, color 0.3s ease',
        fontSize: '0.85rem', // Tamaño de fuente general
    },
    contentWrapper: {
        maxWidth: '960px', // Ancho máximo, puedes ajustar
        margin: '0 auto',
        padding: '0 20px', // Padding horizontal
        textAlign: 'center',
    },
    copyrightText: {
        fontSize: '0.8rem', // Más pequeño
        color: '#555',
        marginBottom: '10px', // Espacio abajo del copyright
        lineHeight: '1.4',
        textAlign: 'center',
    },
    teamName: {
        fontWeight: '600',
        color: '#333',
    },
    mainContent: {
        display: 'flex',
        flexWrap: 'wrap', // Permite que las columnas bajen en pantallas pequeñas
        justifyContent: 'space-around', // Distribuye las columnas
        gap: '20px', // Espacio entre las columnas
        marginBottom: '15px', // Espacio entre las columnas y la cita
        paddingBottom: '10px', // Pequeño padding en la parte inferior
        borderBottom: '1px solid rgba(200,200,200,0.4)', // Línea divisoria sutil
    },
    section: {
        flex: '1 1 250px', // Cada columna intenta ocupar al menos 250px, si no hay espacio, se envuelven
        minWidth: '180px', // Asegura un ancho mínimo para que el contenido no se comprima demasiado
        padding: '5px 10px', // Padding interno para cada sección
        textAlign: 'center', // Alineación central por defecto
        // Media query alternativa para React inline styles (requiere JavaScript)
        // Por simplicidad, lo dejamos centralizado para todos los tamaños o lo ajustas con JS
        // Si necesitas text-left en pantallas grandes, es mejor usar CSS modules o un framework CSS
    },
    sectionTitle: {
        fontSize: '0.95rem', // Títulos un poco más pequeños
        fontWeight: 'bold',
        marginBottom: '8px', // Menos margen abajo del título
        textTransform: 'uppercase',
        color: '#222',
    },
    linkList: {
        listStyle: 'none',
        padding: 0,
        margin: 0,
        lineHeight: '1.3', // Reduce el espaciado entre ítems de la lista
    },
    link: {
        textDecoration: 'none',
        color: '#555',
        fontSize: '0.85rem', // Tamaño de fuente para enlaces
        transition: 'color 0.2s ease, transform 0.2s ease',
        display: 'inline-block', // Permite transformaciones
        '&:hover': {
            color: '#1e7e34', // Un verde un poco más oscuro
            transform: 'translateX(2px)',
        },
    },
    socialIcons: {
        display: 'flex',
        justifyContent: 'center', // Centrar los íconos
        gap: '12px', // Espacio entre los íconos
        marginTop: '5px',
    },
    socialIconLink: {
        textDecoration: 'none',
        display: 'inline-block', // Para que las transformaciones funcionen
    },
    socialIconImage: {
        width: '20px', // Íconos más pequeños para un look compacto
        height: '20px',
        opacity: 0.75, // Un poco de transparencia
        transition: 'opacity 0.2s ease, transform 0.2s ease',
        '&:hover': {
            opacity: 1,
            transform: 'scale(1.1)',
        },
    },
    aboutText: {
        fontSize: '0.8rem', // Texto de descripción más pequeño
        color: '#666',
        lineHeight: '1.4',
        margin: 0, // Elimina márgenes por defecto
    },
    quoteText: {
        fontSize: '0.75rem', // Tamaño de fuente para la cita
        fontStyle: 'italic',
        color: '#777',
        margin: '10px 0 5px 0', // Menos margen
        textAlign: 'center',
    },
    navarroCredit: {
        fontSize: '0.65rem', // Muy pequeño, un detalle discreto
        color: '#888',
        marginTop: '5px', // Margen superior
        textAlign: 'center',
    }
};

export default Footer;
